import requests, time

API_KEY = "YOUR_KEY"
URL = "http://api.terminal-frontier.com"

while True:
    # 1. Perceive
    p = requests.get(f"{URL}/api/perception", headers={"X-API-KEY": API_KEY}).json()
    agent = p['agent']

    # 2. Decision
    if agent['energy'] < 20:
        print("Low Energy - Waiting...")
    elif agent['mass'] >= agent['capacity']:
        print("Cargo Full!")
    else:
        # Check if asteroid in range
        asteroids = [h for h in p['hexes'] if h['resource_type']]
        if asteroids:
            target = asteroids[0]
            if target['q'] == agent['q'] and target['r'] == agent['r']:
                requests.post(f"{URL}/api/intent", json={"action_type": "MINE"}, headers={"X-API-KEY": API_KEY})
            else:
                requests.post(f"{URL}/api/intent", json={"action_type": "MOVE", "data": {"target_q": target['q'], "target_r": target['r']}}, headers={"X-API-KEY": API_KEY})

    time.sleep(90) # Wait for next tick
